template.css:
@page {
  size: A4 portrait;
  margin: 10mm 8mm;
}

.tovarnaya-nakladnaya {
  font-family: Arial, Helvetica, sans-serif;
  font-size: 11px;
  color: #000;
  line-height: 1.25;
}

.doc-title {
  text-align: center;
  font-size: 14px;
  font-weight: 700;
  margin: 0 0 0;
  padding-bottom: 6px;
  border-bottom: 1px solid #000;
}

.parties {
  display: flex;
  justify-content: space-between;
  gap: 16px;
  margin: 10px 0 8px;
}

.party {
  flex: 1 1 50%;
  min-width: 0;
}

.party-line {
  margin: 2px 0;
}

.party-line .label {
  font-weight: 700;
}

.items-table {
  width: 100%;
  border-collapse: collapse;
  table-layout: fixed;
}

.items-table th,
.items-table td {
  border: 1px solid #000;
  padding: 3px 4px;
  vertical-align: middle;
}

.items-table thead th {
  font-weight: 700;
  background: #fff;
}

.col-no {
  width: 4%;
}

.col-name {
  width: 24%;
}

.col-code {
  width: 9%;
}

.col-unit {
  width: 7%;
}

.col-qty {
  width: 7%;
}

.col-price2 {
  width: 10%;
}

.col-price {
  width: 8%;
}

.col-amount2 {
  width: 11%;
}

.col-amount {
  width: 10%;
}

.col-discount {
  width: 10%;
}

.items-table thead .col-no,
.items-table thead .col-unit {
  text-align: center;
}

.items-table thead .col-name,
.items-table thead .col-code {
  text-align: left;
}

.items-table thead .col-qty,
.items-table thead .col-price2,
.items-table thead .col-price,
.items-table thead .col-amount2,
.items-table thead .col-amount,
.items-table thead .col-discount {
  text-align: right;
}

.center {
  text-align: center;
}

.num {
  text-align: right;
  white-space: nowrap;
  font-variant-numeric: tabular-nums;
}

.text {
  text-align: left;
  word-break: break-word;
}

.grand-total td {
  font-weight: 700;
}

.total-label {
  font-weight: 700;
}

.signatures {
  display: flex;
  justify-content: space-between;
  gap: 24px;
  margin-top: 24px;
}

.signature {
  flex: 1 1 45%;
  display: flex;
  align-items: baseline;
  gap: 6px;
}

.signature .label {
  font-weight: 400;
  white-space: nowrap;
}

.signature-line {
  flex: 1 1 auto;
  border-bottom: 1px solid #000;
  min-width: 120px;
  height: 1em;
}
